import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import 'package:shared_preferences/shared_preferences.dart';

class LocalStorageManager {
  final FlutterSecureStorage _secureStorage = FlutterSecureStorage();
  final SharedPreferences _preferences = SharedPreferences.getInstance();

  Future<void> saveAuthToken(String token) async {
    await _secureStorage.write(key: 'auth_token', value: token);
  }

  Future<String?> getAuthToken() async {
    return _secureStorage.read(key: 'auth_token');
  }

  Future<void> saveUserProfile(Map<String, dynamic> profile) async {
    await _preferences.setString('user_profile', jsonEncode(profile));
  }

  Future<Map<String, dynamic>?> getUserProfile() async {
    final String? profileJson = _preferences.getString('user_profile');
    if (profileJson == null) return null;
    return jsonDecode(profileJson);
  }

  Future<void> saveAppConfiguration(Map<String, dynamic> config) async {
    await _preferences.setString('app_configuration', jsonEncode(config));
  }

  Future<Map<String, dynamic>?> getAppConfiguration() async {
    final String? configJson = _preferences.getString('app_configuration');
    if (configJson == null) return null;
    return jsonDecode(configJson);
  }
